'''
Класс для расчета середины ночи, астрономических и гражданских сумерек
'''
from observatory import Observatory
from astropytime import getIers
import numpy as np
from astropy import units as u
from astropy.coordinates import SkyCoord, AltAz, get_sun
from astropy.time import Time

iers_a = getIers()

class SolarTwilight( dict ):
 '''
 return the solar crucial points in scale='utc'
 5 values are calculated:
   sun in Nadir point
   begin of nautical twilight = Nautical0
   end   of nautical twilight = Nautical1
   begin of astronomical twilight = Astronomical0
   end   of astronomical twilight = Astronomical1
 '''
 def __init__(self, observatory, dateOfInterest, method="slow"):
  dict.__init__(self)
  self["iers_a"] = iers_a
  self["observatory"] = observatory["EarthLocation"]
  self["UtcOffset"] = observatory["UtcOffset"]
  self["dateOfInterest"] = Time(dateOfInterest, location=self["observatory"], format='iso')
  self.calculateTwilights(observatory)


 def generateTimeVector( self, timeStart, timeEnd, timeStep ):
  timeVector = np.arange( timeStart.jd, timeEnd.jd, timeStep)
  timeVector = Time( timeVector, location=self["observatory"], format="jd")
  timeVector.delta_ut1_utc = 0.
  #print timeVector[0].utc.isot, timeVector[1].utc.isot
  return( timeVector )

 def calculateSunAltitude( self, timeVector):
  AltAzFrame = AltAz(obstime=timeVector, location=self["observatory"])
  SunAltAzs = get_sun(timeVector).transform_to(AltAzFrame)
  return np.array(SunAltAzs.alt)

 def calculateSunAltAzs( self, timeVector):
  AltAzFrame = AltAz(obstime=timeVector, location=self["observatory"])
  return get_sun(timeVector).transform_to(AltAzFrame)

 def calculateTwilights(self, observatory):

  timeStepHigh =  30.0*u.minute
#  timeStepHigh =  1.0*u.minute
  timeStepLow  =  1.0*u.minute

  
  timeVector = self.generateTimeVector( self["dateOfInterest"], self["dateOfInterest"]+25*u.hour, timeStepHigh.to( u.day ).value )
  timeVector.delta_ut1_utc = 0.
  SunAltitude = self.calculateSunAltitude( timeVector )

  #Midnight
  i_midnight = SunAltitude.argmin()
  self['Midnight'] = timeVector[ i_midnight ]


  timeVector = self.generateTimeVector( self['Midnight']-12*u.hour, self['Midnight']+12*u.hour, timeStepLow.to( u.day ).value )
  timeVector.delta_ut1_utc = 0.
  SunAltAzs = self.calculateSunAltAzs( timeVector )
  SunAltitude = np.array( SunAltAzs.alt )

  #Midnight again ( accuracity less than timeStepLow)
  i_midnight = SunAltitude.argmin()
  self['Midnight'] = timeVector[ i_midnight ]

  #навигационные сумерки
  Twilight = np.abs( SunAltAzs.alt + 12*u.deg )

  #минимальное значение в первой половине массива
  i_minus = Twilight[ 0 : i_midnight ].argmin()
  self['Nautical0'] = timeVector[ 0  : i_midnight ][ i_minus ]

  #минимальное значение во второй половине массива
  i_plus =  Twilight[ i_midnight : -1 ].argmin()
  self['Nautical1'] = timeVector[ i_midnight : -1 ][ i_plus ]

  #астрономические сумерки
  Twilight = np.abs( SunAltAzs.alt + 18*u.deg )

  #минимальное значение в первой половине массива
  i_minus = Twilight[ 0 : i_midnight ].argmin()
  self['Astronomical0'] = timeVector[ 0  : i_midnight ][ i_minus ]

  #минимальное значение во второй половине массива
  i_plus =  Twilight[ i_midnight : -1 ].argmin()
  self['Astronomical1'] = timeVector[ i_midnight : -1 ][ i_plus ]


#  self["TimeVector"] = self.generateTimeVector( self['Midnight']-12*u.hour, self['Midnight']+12*u.hour, timeStepLow.to( u.day ).value )
#  self["AltAzFrame"] = AltAz(obstime=self["TimeVector"], location=self["observatory"])

 def changeTo(self, format="HM"):
  _ret = self.copy()
  for keyword in _ret.keys():
   if isinstance(_ret[keyword], Time):
    _ret[keyword] = Time(_ret[keyword].iso, location=self["observatory"], format='iso', out_subfmt="date_hm")
    #_ret[keyword].delta_ut1_utc = _ret[keyword].get_delta_ut1_utc(self["iers_a"])
    _ret[keyword] = (_ret[keyword]+self["UtcOffset"]).iso.split()[-1]
  return _ret

